const coreItems = $input.all();
const coreCards = $('핵심 필터').all().map(function(c){ var p=c.json.properties||{}; return (p.주제 && p.주제.title && p.주제.title[0]) ? p.주제.title[0].plain_text : ''; }).filter(Boolean);
const header = '아래는 보맵 핵심 컨텍스트 카드(' + coreCards.join(', ') + ')의 본문입니다.\n\n';
const coreText = header + coreItems.map(function(b){ return (b.json.content || ''); }).filter(Boolean).join('\n');
const all = $('허브 카드 조회').all();
const detail = all.filter(function(c){ var p=c.json.properties||{}; return p.계층 && p.계층.select && p.계층.select.name === '디테일'; });
const menu = detail.map(function(c){
  var p = c.json.properties || {};
  var subj = (p.주제 && p.주제.title && p.주제.title[0]) ? p.주제.title[0].plain_text : '';
  var area = (p.영역 && p.영역.select) ? p.영역.select.name : '';
  var jobsArr = (p['관련 직무'] && p['관련 직무'].multi_select) ? p['관련 직무'].multi_select.map(function(x){ return x.name; }) : [];
  return '- [' + subj + '] 영역:' + area + ' / 직무:' + jobsArr.join(',') + ' / id:' + c.json.id;
}).join('\n');
return [{ json: { coreContext: coreText, detailMenu: menu } }];

